            <div v-if="form.meeting_link" class="px-6 py-4">
              <dt class="mb-1 text-sm text-gray-500 dark:text-gray-400">Meeting Link</dt>
              <dd><a :href="form.meeting_link" target="_blank" class="break-all text-sm text-blue-600 hover:underline dark:text-blue-400">{{ form.meeting_link }}</a></dd>
            </div>
          </dl>
        </div>

        <div v-if="submitError" class="mt-4 rounded-lg border border-red-200 bg-red-50 p-4 dark:border-red-800 dark:bg-red-900/20">
          <p class="text-sm text-red-700 dark:text-red-400">{{ submitError }}</p>
        </div>

        <div class="mt-8 flex justify-between">
          <button @click="prevStep" class="tm-btn-secondary">Back</button>
          <button @click="submitTeamMeeting" :disabled="isSubmitting" class="tm-btn-primary inline-flex items-center gap-2">
            <LoadingSpinner v-if="isSubmitting" size="sm" class="!text-white" />
            {{ isSubmitting ? 'Creating...' : 'Create Meeting' }}
          </button>
        </div>
      </div>

      <!-- Success -->
      <div v-if="currentStep === 7" class="py-16 text-center">
        <div class="mx-auto mb-5 flex h-20 w-20 items-center justify-center rounded-full bg-green-100 dark:bg-green-900/30">
          <svg class="h-10 w-10 text-green-600 dark:text-green-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <h2 class="text-2xl font-bold text-gray-900 dark:text-white">Team Meeting Created!</h2>
        <p class="mt-2 text-gray-500 dark:text-gray-400">Invitations will be sent to all participants.</p>
        <div class="mt-8 flex justify-center gap-3">
          <button @click="router.push(`/bookings/${meetingResult?.booking_id}`)" class="tm-btn-primary">View Meeting</button>
          <button @click="resetWizard" class="tm-btn-secondary">Schedule Another</button>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, reactive, computed } from "vue";
import { useRouter } from "vue-router";
import { createResource, call } from "frappe-ui";
import { useAuthStore } from "@/stores/auth";
import LoadingSpinner from "@/components/shared/LoadingSpinner.vue";

const router = useRouter();
const auth = useAuthStore();

const currentStep = ref(0);
const isSubmitting = ref(false);
const submitError = ref("");
const meetingResult = ref(null);

const form = reactive({
  department: "",
  meeting_type: "",
  participants: [],
  scheduled_date: "",
  scheduled_start_time: "",
  meeting_agenda: "",
  meeting_notes: "",
  meeting_link: "",
});

const selectedDeptName = ref("");
const selectedMeetingTypeName = ref("");
const selectedMeetingDuration = ref(0);

const wizardSteps = computed(() => [
  { id: "department", label: "Department" },
  { id: "meeting_type", label: "Meeting Type" },
  { id: "participants", label: "Participants" },
  { id: "date", label: "Date" },
  { id: "time", label: "Time" },
  { id: "details", label: "Details" },
  { id: "review", label: "Confirm" },
]);

function stepClass(idx) {
  if (idx < currentStep.value) return "text-blue-600 dark:text-blue-400 cursor-pointer hover:bg-blue-50 dark:hover:bg-blue-900/20";
  if (idx === currentStep.value) return "text-blue-600 dark:text-blue-400 font-semibold";
  return "text-gray-400 dark:text-gray-500 cursor-default";
}

// Calendar
const viewMonth = ref(new Date().getMonth() + 1);
const viewYear = ref(new Date().getFullYear());

const monthLabel = computed(() => {
  const d = new Date(viewYear.value, viewMonth.value - 1, 1);
  return d.toLocaleDateString("en-US", { month: "long", year: "numeric" });
});

const canGoPrevMonth = computed(() => {
  const now = new Date();
  return viewYear.value > now.getFullYear() || (viewYear.value === now.getFullYear() && viewMonth.value > now.getMonth() + 1);
});

const calendarDays = computed(() => {
  const year = viewYear.value;
  const month = viewMonth.value - 1;
  const firstDay = new Date(year, month, 1);
  const lastDay = new Date(year, month + 1, 0);
  const startDow = (firstDay.getDay() + 6) % 7;
  const daysInMonth = lastDay.getDate();
  const availSet = new Set(teamAvailableDates.data?.available_dates || []);
  const today = new Date().toISOString().split("T")[0];
  const days = [];
  for (let i = 0; i < startDow; i++) days.push({ date: null, day: null, available: false });
  for (let d = 1; d <= daysInMonth; d++) {
    const dateStr = `${year}-${String(month + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
    days.push({ date: dateStr, day: d, available: availSet.has(dateStr) && dateStr >= today });
  }
  return days;
});

function changeMonth(delta) {
  let m = viewMonth.value + delta;
  let y = viewYear.value;
  if (m > 12) { m = 1; y++; }
  if (m < 1) { m = 12; y--; }
  viewMonth.value = m;
  viewYear.value = y;
  teamAvailableDates.fetch();
}

function dateClass(day) {
  if (form.scheduled_date === day.date) return "bg-blue-600 text-white font-bold shadow-md dark:bg-blue-500";
  if (day.available) return "text-gray-900 hover:bg-blue-50 hover:text-blue-700 dark:text-white dark:hover:bg-blue-900/20";
  return "text-gray-300 dark:text-gray-600 cursor-not-allowed";
}

// APIs
const BOOKING_API = "meeting_manager.meeting_manager.api.booking";

const ledDepartments = createResource({
  url: `${BOOKING_API}.get_led_departments`,
  auto: true,
});

const meetingTypes = createResource({
  url: `${BOOKING_API}.get_internal_meeting_types`,
  makeParams() { return { department: form.department }; },
});

const departmentMembers = createResource({
  url: `${BOOKING_API}.get_department_members`,
  makeParams() { return { department: form.department }; },
});

const teamAvailableDates = createResource({
  url: `${BOOKING_API}.get_team_available_dates`,
  makeParams() {
    return {
      department: form.department,
      meeting_type: form.meeting_type,
      month: viewMonth.value,
      year: viewYear.value,
      participants: JSON.stringify(allParticipants.value),
    };
  },
});

const teamAvailableSlots = createResource({
  url: `${BOOKING_API}.get_team_available_slots`,
  makeParams() {
    return {
      department: form.department,
      meeting_type: form.meeting_type,
      date: form.scheduled_date,
      participants: JSON.stringify(allParticipants.value),
    };
  },
});

const timeSlots = computed(() => teamAvailableSlots.data?.available_slots || []);

// Host is always the current user
const hostMember = computed(() => {
  if (!departmentMembers.data) return null;
  return departmentMembers.data.find(m => m.user_id === auth.user || m.email === auth.user) || null;
});

const otherMembers = computed(() => {
  if (!departmentMembers.data) return [];
  const hostUser = auth.user;
  return departmentMembers.data.filter(m => m.user_id !== hostUser && m.email !== hostUser);
});

// All participants = host + selected members
const allParticipants = computed(() => {
  const host = auth.user;
  return [host, ...form.participants.filter(p => p !== host)];
});

const selectedMembersInfo = computed(() => {
  if (!departmentMembers.data) return [];
  const hostUser = auth.user;
  return form.participants.filter(p => p !== hostUser).map(userId => {
    const member = departmentMembers.data.find(m => m.user_id === userId);
    return {
      user_id: userId,
      full_name: member?.full_name || userId,
      email: member?.email || userId,
    };
  });
});

// Per-participant notification toggles (default ON)
const notifyParticipants = reactive({});

function toggleNotify(userId) {
  notifyParticipants[userId] = !notifyParticipants[userId];
}

function setAllNotify(value) {
  for (const member of selectedMembersInfo.value) {
    notifyParticipants[member.user_id] = value;
  }
}

// Initialize notify toggles when participants change
function ensureNotifyDefaults() {
  for (const p of form.participants) {
    if (p !== auth.user && !(p in notifyParticipants)) {
      notifyParticipants[p] = true;
    }
  }
}

function initials(name) {
  if (!name) return "?";
  const parts = name.split(/\s+/);
  if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase();
  return name.substring(0, 2).toUpperCase();
}

const allOthersSelected = computed(() => {
  return otherMembers.value.length > 0 && otherMembers.value.every(m => form.participants.includes(m.user_id));
});

function toggleParticipant(user) {
  const idx = form.participants.indexOf(user);
  if (idx >= 0) {
    form.participants.splice(idx, 1);
  } else {
    form.participants.push(user);
  }
}

function toggleAllParticipants() {
  if (allOthersSelected.value) {
    // Deselect all others
    form.participants = [];
  } else {
    // Select all others
    form.participants = otherMembers.value.map(m => m.user_id);
  }
}

function selectDepartment(dept) {
  form.department = dept.name;
  selectedDeptName.value = dept.department_name;
  form.meeting_type = "";
  form.participants = [];
  form.scheduled_date = "";
  form.scheduled_start_time = "";
}

function selectMeetingType(mt) {
  form.meeting_type = mt.name;
  selectedMeetingTypeName.value = mt.meeting_name;
  selectedMeetingDuration.value = mt.duration;
  form.scheduled_date = "";
  form.scheduled_start_time = "";
}

function selectDate(dateStr) {
  form.scheduled_date = dateStr;
  form.scheduled_start_time = "";
}

function nextStep() {
  if (currentStep.value === 0 && form.department) {
    meetingTypes.fetch();
    departmentMembers.fetch();
  }
  if (currentStep.value === 2 && form.participants.length >= 1) {
    teamAvailableDates.fetch();
  }
  if (currentStep.value === 3 && form.scheduled_date) {
    teamAvailableSlots.fetch();
  }
  if (currentStep.value === 5) {
    // Entering review step - ensure notify defaults
    ensureNotifyDefaults();
  }
  currentStep.value++;
}

function prevStep() { currentStep.value--; }

function goToStep(idx) {
  if (idx < currentStep.value) currentStep.value = idx;
}

function formatDate(dateStr) {
  if (!dateStr) return "";
  const d = new Date(dateStr + "T00:00:00");
  return d.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric", year: "numeric" });
}

function formatTime(timeStr) {
  if (!timeStr) return "";
  const [h, m] = timeStr.split(":");
  return `${h}:${m}`;
}

async function submitTeamMeeting() {
  isSubmitting.value = true;
  submitError.value = "";
  try {
    // Build list of participants to notify (only those with toggle ON, excluding host)
    const participantsToNotify = form.participants
      .filter(p => p !== auth.user && notifyParticipants[p]);

    const result = await call(`${BOOKING_API}.create_team_meeting`, {
      meeting_data: {
        department: form.department,
        meeting_type: form.meeting_type,
        scheduled_date: form.scheduled_date,
        scheduled_start_time: form.scheduled_start_time,
        participants: allParticipants.value,
        meeting_agenda: form.meeting_agenda,
        meeting_notes: form.meeting_notes,
        meeting_link: form.meeting_link,
        notify_participants: participantsToNotify.length > 0 ? participantsToNotify : false,
      },
    });
    meetingResult.value = result;
    currentStep.value = 7;
  } catch (e) {
    submitError.value = e.messages?.[0] || e.message || "Failed to create meeting";
  } finally {
    isSubmitting.value = false;
  }
}

function resetWizard() {
  currentStep.value = 0;
  Object.assign(form, {
    department: "", meeting_type: "", participants: [],
    scheduled_date: "", scheduled_start_time: "",
    meeting_agenda: "", meeting_notes: "", meeting_link: "",
  });
  meetingResult.value = null;
  submitError.value = "";
}
</script>

<style scoped>
.tm-btn-primary {
  @apply cursor-pointer rounded-lg bg-blue-600 px-6 py-2.5 text-sm font-semibold text-white shadow-sm transition-colors hover:bg-blue-700 disabled:cursor-not-allowed disabled:opacity-50;
}
.tm-btn-secondary {
  @apply cursor-pointer rounded-lg bg-gray-100 px-6 py-2.5 text-sm font-medium text-gray-700 transition-colors hover:bg-gray-200 dark:bg-gray-700 dark:text-gray-300 dark:hover:bg-gray-600;
}
.tm-input {
  @apply w-full rounded-lg border border-gray-300 bg-white px-3 py-2.5 text-sm text-gray-900 placeholder-gray-400 focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 dark:border-gray-600 dark:bg-gray-700 dark:text-white dark:placeholder-gray-500;
}
.tm-label {
  @apply mb-1 block text-xs font-medium text-gray-500 dark:text-gray-400;
}
</style>
